oxy_webhelp_navlinks = {"saas_authentication-d30753e11625":{"topics":[{"title":"Multifactor authentication methods","shortdesc":"<p class=\"shortdesc\">Multifactor authentication is a multi-step login process that enhances security by         requiring multiple verification methods, reducing the risk of account compromise from stolen         credentials.<\/p>","href":"saas\/common\/mfa_methods.html","attributes":{"data-id":"mfa_methods"},"menu":{"hasChildren":false},"tocID":"mfa_methods-d30753e11638","topics":[]},{"title":"Configuring MFA and login settings","shortdesc":"<p class=\"shortdesc\">Configure how local users log in to <span class=\"ph\">RSC<\/span> using passkeys and TOTP         through an authenticator app.<\/p>","href":"saas\/common\/configuring_mfa_login_settings.html","attributes":{"data-id":"configuring_mfa_login_settings"},"menu":{"hasChildren":false},"tocID":"configuring_mfa_login_settings-d30753e11649","topics":[]},{"title":"Rubrik MFA with TOTP","shortdesc":"<p class=\"shortdesc\">The Rubrik two-step verification feature uses time-based one-time passwords in         addition to the user login credentials to enforce multi-factor authentication on user         accounts.<\/p>","href":"saas\/common\/rsc_rmfa_totp_2.html","attributes":{"data-id":"rsc_rmfa_totp"},"menu":{"hasChildren":false},"tocID":"rsc_rmfa_totp-d30753e11663","next":"rsc_rmfa_totp-d30753e11663"},{"title":"Passkeys for MFA","shortdesc":"<p class=\"shortdesc\">Passkeys provide an alternative MFA method in <span class=\"ph\">RSC<\/span> using biometrics or         hardware security keys to verify identity and enable passwordless login.<\/p>","href":"saas\/passkeys_mfa.html","attributes":{"data-id":"passkeys_mfa"},"menu":{"hasChildren":false},"tocID":"passkeys_mfa-d30753e11735","next":"passkeys_mfa-d30753e11735"}]}};